mapper.select:
select vhi.hr_id , thicm.user_id , case when thja.write_year is null then 'I' else 'U' end as cmd , case when thja.write_year is null then #{writeYear} else thja.write_year end as write_year , case when thja.doc_type is null then 'JOB' else thja.doc_type end as doc_type , thja.comp_id , thja.doc_no , vhi.hr_nm , toi.orgn_nm , thij.jbrp_nm , thja.backup_hr_id , vhi2.hr_nm as backup_hr_nm , thja.assign_task , case when thja.doc_no is null then 'Y' else thja.use_yn end as use_yn , thja.created_at , thja.created_by , thja.updated_at , thja.updated_by , ( select count(*) from esg.tb_task_manager_detail ttmd where ttmd.task_detail_user_id = vhi.user_id and to_char(ttmd.req_dt, 'YYYYMMDD') like write_year||'%' and ttmd.comp_id = #{compId} and ttmd.complete_dt is null and ttmd.cancel_dt is null and ttmd.use_yn = 'Y' ) as not_completed_cnt from esg.v_hr_info vhi left join esg.tb_hr_info_comp_map thicm on vhi.hr_id = thicm.hr_id left join esg.tb_orgn_info toi on vhi.orgn_id = toi.orgn_id left join esg.tb_hr_info_jbrp thij on thij.jbrp_id = vhi.jbrp and thij.comp_id = #{compId} left join esg.tb_hse_job_assignment thja on vhi.hr_id = thja.hr_id and thicm.comp_id = thja.comp_id
and thja.write_year = #{writeYear}
and thja.doc_no = #{docNo}
LEFT JOIN esg.v_hr_info vhi2 on thja.backup_hr_id = vhi2.hr_id where 1=1 and thicm.comp_id = #{compId} and vhi.use_yn = 'Y'
and to_char(vhi.created_at, 'YYYY') <= #{writeYear}
and vhi.hr_id = #{hrId}
order by vhi.ord_seq asc, write_year desc, thja.doc_no asc

mapper.update:
UPDATE esg.tb_hse_job_assignment
SET
    hr_id = #{hrId},
    backup_hr_id = #{backupHrId},
    assign_task = #{assignTask},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

mapper.delete:
UPDATE esg.tb_hse_job_assignment
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

