WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

  SELECT doc_no,
         write_year
    FROM esg.tb_hse_job_assignment
   WHERE comp_id = #{compId}
     AND hr_id = #{currentUserHrId}
     AND doc_type = #{docType}
ORDER BY write_year DESC
         LIMIT 1;
